-- ============================================================
-- V502: Upgrade all EMAIL templates to styled HTML and add new templates
-- ============================================================

-- Helper: Reusable HTML wrapper for all emails
-- Each UPDATE below wraps the content in a branded ForexBridge email layout.

-- ── Transaction Status Updates ──

UPDATE notification_templates SET body_template =
'<!DOCTYPE html><html><head><meta charset="UTF-8"></head><body style="margin:0;padding:0;font-family:''Segoe UI'',sans-serif;background:#f4f6f9;"><table width="100%" cellspacing="0" cellpadding="0" style="max-width:600px;margin:0 auto;padding:40px 20px;"><tr><td style="background:#1B3571;padding:24px;text-align:center;border-radius:12px 12px 0 0;"><h1 style="color:#fff;margin:0;font-size:24px;">ForexBridge</h1></td></tr><tr><td style="background:#fff;padding:32px 24px;border-radius:0 0 12px 12px;box-shadow:0 2px 8px rgba(0,0,0,0.06);"><h2 style="color:#1B3571;margin:0 0 16px;font-size:20px;">Transfer Created</h2><p style="color:#4a5568;font-size:15px;line-height:1.6;">Hi {{firstName}},</p><p style="color:#4a5568;font-size:15px;line-height:1.6;">Your transfer <strong>{{referenceNumber}}</strong> has been created.</p><table style="width:100%;background:#f8f9fb;border-radius:8px;padding:16px;margin:16px 0;" cellpadding="8"><tr><td style="color:#718096;font-size:13px;">You Send</td><td style="text-align:right;font-weight:600;color:#1B3571;">{{sendAmount}} {{sendCurrency}}</td></tr><tr><td style="color:#718096;font-size:13px;">Recipient Gets</td><td style="text-align:right;font-weight:600;color:#059669;">{{receiveAmount}} {{receiveCurrency}}</td></tr><tr><td style="color:#718096;font-size:13px;">Recipient</td><td style="text-align:right;font-weight:500;">{{beneficiaryName}}</td></tr><tr><td style="color:#718096;font-size:13px;">Rate</td><td style="text-align:right;font-family:monospace;">{{exchangeRate}}</td></tr><tr><td style="color:#718096;font-size:13px;">Fee</td><td style="text-align:right;">{{feeAmount}} {{feeCurrency}}</td></tr></table><hr style="border:none;border-top:1px solid #e2e8f0;margin:24px 0;"><p style="color:#a0aec0;font-size:12px;text-align:center;">ForexBridge — Secure International Money Transfers</p></td></tr></table></body></html>'
WHERE template_code = 'TX_CREATED' AND channel = 'EMAIL' AND language = 'en';

UPDATE notification_templates SET body_template =
'<!DOCTYPE html><html><head><meta charset="UTF-8"></head><body style="margin:0;padding:0;font-family:''Segoe UI'',sans-serif;background:#f4f6f9;"><table width="100%" cellspacing="0" cellpadding="0" style="max-width:600px;margin:0 auto;padding:40px 20px;"><tr><td style="background:#1B3571;padding:24px;text-align:center;border-radius:12px 12px 0 0;"><h1 style="color:#fff;margin:0;font-size:24px;">ForexBridge</h1></td></tr><tr><td style="background:#fff;padding:32px 24px;border-radius:0 0 12px 12px;box-shadow:0 2px 8px rgba(0,0,0,0.06);"><h2 style="color:#1B3571;margin:0 0 16px;font-size:20px;">Transfer Completed!</h2><p style="color:#4a5568;font-size:15px;line-height:1.6;">Hi {{firstName}},</p><p style="color:#4a5568;font-size:15px;line-height:1.6;">Great news! Your transfer <strong>{{referenceNumber}}</strong> has been successfully delivered.</p><div style="background:#ecfdf5;border-radius:8px;padding:16px;text-align:center;margin:16px 0;"><p style="color:#059669;font-size:22px;font-weight:700;margin:0;">{{receiveAmount}} {{receiveCurrency}}</p><p style="color:#065f46;font-size:13px;margin:4px 0 0;">delivered to {{beneficiaryName}}</p></div><hr style="border:none;border-top:1px solid #e2e8f0;margin:24px 0;"><p style="color:#a0aec0;font-size:12px;text-align:center;">ForexBridge — Secure International Money Transfers</p></td></tr></table></body></html>'
WHERE template_code = 'TX_PAID' AND channel = 'EMAIL' AND language = 'en';

UPDATE notification_templates SET body_template =
'<!DOCTYPE html><html><head><meta charset="UTF-8"></head><body style="margin:0;padding:0;font-family:''Segoe UI'',sans-serif;background:#f4f6f9;"><table width="100%" cellspacing="0" cellpadding="0" style="max-width:600px;margin:0 auto;padding:40px 20px;"><tr><td style="background:#1B3571;padding:24px;text-align:center;border-radius:12px 12px 0 0;"><h1 style="color:#fff;margin:0;font-size:24px;">ForexBridge</h1></td></tr><tr><td style="background:#fff;padding:32px 24px;border-radius:0 0 12px 12px;box-shadow:0 2px 8px rgba(0,0,0,0.06);"><h2 style="color:#dc2626;margin:0 0 16px;font-size:20px;">Transfer Failed</h2><p style="color:#4a5568;font-size:15px;line-height:1.6;">Hi {{firstName}},</p><p style="color:#4a5568;font-size:15px;line-height:1.6;">Unfortunately, your transfer <strong>{{referenceNumber}}</strong> could not be completed.</p><div style="background:#fef2f2;border-left:4px solid #dc2626;border-radius:4px;padding:12px 16px;margin:16px 0;"><p style="color:#991b1b;font-size:14px;margin:0;"><strong>Reason:</strong> {{reason}}</p></div><p style="color:#4a5568;font-size:15px;line-height:1.6;">Please contact our support team for assistance.</p><hr style="border:none;border-top:1px solid #e2e8f0;margin:24px 0;"><p style="color:#a0aec0;font-size:12px;text-align:center;">ForexBridge — Secure International Money Transfers</p></td></tr></table></body></html>'
WHERE template_code = 'TX_FAILED' AND channel = 'EMAIL' AND language = 'en';

