UPDATE notification_templates SET body_template =
'<!DOCTYPE html><html><head><meta charset="UTF-8"></head><body style="margin:0;padding:0;font-family:''Segoe UI'',sans-serif;background:#f4f6f9;"><table width="100%" cellspacing="0" cellpadding="0" style="max-width:600px;margin:0 auto;padding:40px 20px;"><tr><td style="background:#1B3571;padding:24px;text-align:center;border-radius:12px 12px 0 0;"><h1 style="color:#fff;margin:0;font-size:24px;">ForexBridge</h1></td></tr><tr><td style="background:#fff;padding:32px 24px;border-radius:0 0 12px 12px;box-shadow:0 2px 8px rgba(0,0,0,0.06);"><h2 style="color:#059669;margin:0 0 16px;font-size:20px;">Account Upgraded!</h2><p style="color:#4a5568;font-size:15px;line-height:1.6;">Hi {{firstName}},</p><p style="color:#4a5568;font-size:15px;line-height:1.6;">Congratulations! Your account has been upgraded.</p><div style="background:#ecfdf5;border-radius:8px;padding:20px;text-align:center;margin:16px 0;"><p style="color:#065f46;font-size:13px;margin:0 0 4px;">Your new tier</p><p style="color:#059669;font-size:24px;font-weight:700;margin:0;">{{newTier}}</p></div><p style="color:#4a5568;font-size:15px;line-height:1.6;">You now have access to higher transaction limits and additional features.</p><hr style="border:none;border-top:1px solid #e2e8f0;margin:24px 0;"><p style="color:#a0aec0;font-size:12px;text-align:center;">ForexBridge — Secure International Money Transfers</p></td></tr></table></body></html>'
